function [e2In,e2Out,indIn,indOut,indPk] = fGetE2Width(x,y)%% Returns 1/e^2 width.%% [e2In,e2Out,indIn,indOut,indPk] = fGetE2Width(x,y)%% x: axis information (x axis)% y: counts for each point (yaxis)%% e2In: fwhm from peak% e2Out: fwhm from edge% indIn, indxOut: 2*1 array, index for each point% indPk: index for peak%%% revision history% copyright Kei Nakamura% ver.1, 2018/8/23: created%%% in case of wrong inputif sum(y)==0||numel(x)<=3    e2In = 0;    e2Out = 0;    indIn = 0;    indOut = 0;    indPk = 1;else    %% obtain peak, split into 2    [maxV,indPk] = max(y);      % max value and max index for counts    rightX = x(indPk:end);         % right side of the peak    rightY = y(indPk:end);         % right side of the peak    leftX = x(1:indPk);             % left side of the peak    leftY = y(1:indPk);             % left side of the peak        % right side, from edge    k2 = find(rightY>exp(-2)*maxV,1,'last');    v2 = rightX(k2);    % right side, from peak    k1 = find(rightY<exp(-2)*maxV,1,'first');        if isempty(k1)        if isempty(k2)            k1=1;k2=1;        else% in case never go below 0.5*peak        k1 = k2;        end    else k1 = k1 - 1; % one step back to be consistent with k2    end    v1 = rightX(k1);        % left side, from edge    k4 = find(leftY>exp(-2)*maxV,1,'first');    v4 = leftX(k4);        % left side, from peak    k3 = find(leftY<exp(-2)*maxV,1,'last');    if isempty(k3) % in case never go below 0.5*peak        if isempty(k4)            k3=1;k4=1;        else        k3 = k4;        end    else k3 = k3 + 1; % one step ahead to be consistent with k2    end    v3 = leftX(k3);         e2In = abs(v1 - v3)/2;        e2Out = abs(v2 - v4)/2;        indIn(1) = k3;    indOut(1) = k4;    indIn(2) = k1 + indPk-1;    indOut(2) = k2 + indPk-1;    end
